"""Updated visualization functions for opsin analysis that use the global color scheme."""import osimport matplotlib.pyplot as pltfrom matplotlib.colors import BoundaryNorm, ListedColormapfrom collections import Counterfrom matplotlib.patches import Patchimport numpy as npimport pandas as pdimport plotly.graph_objects as goimport seaborn as snsfrom scipy.cluster.hierarchy import linkage, dendrogramfrom scipy.spatial.distance import squareform, cdistimport logomaker # Keep this import at the top# Import our color schemefrom src.opsin_color_scheme import (    OPSIN_COLORS, RMSD_CMAP, RMSD_COMPACT_CMAP, DIVERGING_CMAP, RMSD_DISCRETE_CMAP, RMSD_BOUNDS,    HELIX_COLORS, HELIX_COLORS_STR, HELIX_COLORS_LIST, get_group_colors)def plot_rmsd_heatmap(rmsd_df, title="All-vs-All RMSD Heatmap"):    """Visualize the RMSD matrix as a heatmap using the global color scheme."""    plt.figure(figsize=(10, 8))    # Use our custom compact colormap for RMSD values    vmax = 3.0  # Max value for color scale (anything above will be yellow)    sns.heatmap(rmsd_df, annot=True, fmt=".2f", cmap=RMSD_COMPACT_CMAP, vmin=0, vmax=vmax)    plt.title(title)    plt.xlabel("Structure")    plt.ylabel("Structure")    plt.tight_layout()    return plt.gcf()def plot_similarity_tree(rmsd_df, title="Structural Similarity Tree"):    """Generate a dendrogram based on RMSD values with consistent colors."""    matrix = rmsd_df.fillna(rmsd_df.max().max()).values    condensed = squareform(matrix)    Z = linkage(condensed, method='average')    plt.figure(figsize=(12, 8))    # Use a consistent function for branch colors    def link_color_func(k):        return OPSIN_COLORS['gray_dark']    dendrogram(        Z,        labels=rmsd_df.index,        leaf_rotation=45,        link_color_func=link_color_func    )    plt.title(title)    plt.xlabel("Structure")    plt.ylabel("RMSD (Å)")    plt.tight_layout()    return plt.gcf()def create_residue_conservation_plot(msa_df, helix_highlighting=True, figsize=(12, 8)):    """    Create a heatmap showing conservation levels at each position in the MSA.    Handles both dot notation (1.50) and x notation (1x50) GRN formats.    Args:        msa_df: MSA DataFrame with GRN column names        helix_highlighting: Whether to color-code positions by helix        figsize: Figure size tuple    Returns:        Matplotlib figure    """    # Extract residue types from MSA (first character of each cell)    residue_df = msa_df.map(lambda x: x[0] if isinstance(x, str) and len(x) > 0 and x != '-' else '-')    # Calculate conservation percentage    conservation = {}    for col in residue_df.columns:        # Count residue types at this position        counts = residue_df[col].value_counts()        total = (residue_df[col] != '-').sum()  # Don't count gaps        if total > 0:            # Calculate percentage of most common residue            top_res = counts.index[0] if not counts.empty else '-'            if top_res != '-':                top_pct = (counts[top_res] / total) * 100            else:                # If top residue is a gap, use the next one                top_res = counts.index[1] if len(counts) > 1 else '-'                top_pct = (counts[top_res] / total) * 100 if top_res != '-' else 0            conservation[col] = {                'residue': top_res,                'percentage': top_pct            }        else:            conservation[col] = {                'residue': '-',                'percentage': 0            }    # Create a DataFrame with position, helix, and conservation data    plot_data = []    for pos, data in conservation.items():        pos_str = str(pos) # Ensure pos is treated as string for parsing        # Handle different GRN formats        if 'x' in pos_str:            # Handle 1x50 format (transmembrane helices)            try:                helix, num_str = pos_str.split('x')                num = float(num_str) if num_str.replace('.', '', 1).isdigit() else 0                if helix.isdigit():                    plot_data.append({                        'Position': pos, 'Helix': helix, 'Position_Num': num,                        'Residue': data['residue'], 'Conservation': data['percentage']                    })                else: # Non-numeric helix                    plot_data.append({                        'Position': pos, 'Helix': 'Other', 'Position_Num': num,                        'Residue': data['residue'], 'Conservation': data['percentage']                    })            except ValueError: # Fallback for malformed positions like 'AxB'                plot_data.append({                    'Position': pos, 'Helix': 'Other', 'Position_Num': 0,                    'Residue': data['residue'], 'Conservation': data['percentage']                })        elif '.' in pos_str:            parts = pos_str.split('.')            num_after_dot = float(parts[1]) if len(parts) > 1 and parts[1].replace('.', '', 1).isdigit() else 0            if pos_str.startswith('L.'):                plot_data.append({'Position': pos, 'Helix': 'L', 'Position_Num': num_after_dot, 'Residue': data['residue'], 'Conservation': data['percentage']})            elif pos_str.startswith('n.'):                plot_data.append({'Position': pos, 'Helix': 'N', 'Position_Num': num_after_dot, 'Residue': data['residue'], 'Conservation': data['percentage']})            elif pos_str.startswith('c.'):                plot_data.append({'Position': pos, 'Helix': 'C', 'Position_Num': num_after_dot, 'Residue': data['residue'], 'Conservation': data['percentage']})            elif len(parts) == 2 and parts[0].isdigit(): # Standard helix.position (1.50)                plot_data.append({'Position': pos, 'Helix': parts[0], 'Position_Num': num_after_dot, 'Residue': data['residue'], 'Conservation': data['percentage']})            elif len(parts) >= 2 and len(parts[0]) == 2 and parts[0].isdigit(): # Loop AB.CCC (12.003)                plot_data.append({'Position': pos, 'Helix': 'L', 'Position_Num': float('0.' + parts[1]) if parts[1].isdigit() else 0, 'Residue': data['residue'], 'Conservation': data['percentage']})            else: # Other dot formats                plot_data.append({'Position': pos, 'Helix': 'Other', 'Position_Num': 0, 'Residue': data['residue'], 'Conservation': data['percentage']})        else: # Numeric or other labels            plot_data.append({                'Position': pos, 'Helix': 'Other',                'Position_Num': float(pos) if pos_str.replace('.', '', 1).isdigit() else 0,                'Residue': data['residue'], 'Conservation': data['percentage']            })    conservation_df = pd.DataFrame(plot_data)    if 'Helix' in conservation_df.columns and not conservation_df['Helix'].isna().all():        def helix_sort_key(h_val): # Renamed h to h_val            h_str = str(h_val) # Ensure it's a string for .isdigit()            if h_str.isdigit(): return int(h_str)            elif h_str == 'N': return -1            elif h_str == 'L': return 10            elif h_str == 'C': return 11            else: return 12        conservation_df['Helix_Sort'] = conservation_df['Helix'].apply(helix_sort_key)        conservation_df = conservation_df.sort_values(['Helix_Sort', 'Position_Num'])    else:        conservation_df = conservation_df.sort_values('Position')    fig, ax = plt.subplots(figsize=figsize)    x = np.arange(len(conservation_df))    bars = ax.bar(x, conservation_df['Conservation'], width=0.8)    if helix_highlighting and 'Helix' in conservation_df.columns:        for i, (_, row) in enumerate(conservation_df.iterrows()):            helix = str(row['Helix']) # Ensure string for .isdigit()            if helix.isdigit() and int(helix) in HELIX_COLORS:                bars[i].set_color(HELIX_COLORS[int(helix)])            elif helix == 'L': bars[i].set_color(OPSIN_COLORS['gray_light'])            elif helix == 'N': bars[i].set_color(OPSIN_COLORS['blue_light'])            elif helix == 'C': bars[i].set_color(OPSIN_COLORS['green'])            else: bars[i].set_color(OPSIN_COLORS['gray_dark'])    for i, (_, row) in enumerate(conservation_df.iterrows()):        if row['Conservation'] > 5:            ax.text(i, row['Conservation'] + 2, row['Residue'],                    ha='center', va='bottom', fontweight='bold')    ax.set_ylabel('Conservation (%)', fontsize=12)    ax.set_xlabel('Position', fontsize=12)    ax.set_title('Residue Conservation by Position', fontsize=14)    ax.set_xticks(x)    ax.set_xticklabels(conservation_df['Position'], rotation=90)    ax.axhline(y=50, color=OPSIN_COLORS['gray_light'], linestyle='--', alpha=0.7)    ax.set_ylim(0, 105)    ax.grid(axis='y', alpha=0.3)    if helix_highlighting:        legend_elements = []        for i in range(1, 8):            if i in HELIX_COLORS:                legend_elements.append(Patch(facecolor=HELIX_COLORS[i], label=f'Helix {i}'))        legend_elements.extend([            Patch(facecolor=OPSIN_COLORS['blue_light'], label='N-terminal'),            Patch(facecolor=OPSIN_COLORS['gray_light'], label='Loop'),            Patch(facecolor=OPSIN_COLORS['green'], label='C-terminal')        ])        ax.legend(handles=legend_elements, loc='upper right')    plt.tight_layout()    return figdef visualize_rmsd_heatmap(rmsd_df, structure_ids, group_dict=None, domain_dict=None, name_dict=None,                           annot=False, font_scale=1.0, group_by='molecular_function', error_threshold=3.0):    """    Visualize RMSD matrix as a heatmap with our consistent color scheme.    Args:        rmsd_df: DataFrame with RMSD values        structure_ids: List of structure IDs        group_dict: Dictionary mapping structure IDs to molecular function groups        domain_dict: Dictionary mapping structure IDs to domain groups        name_dict: Dictionary mapping structure IDs to display names        annot: Whether to annotate the heatmap with values (default: False)        font_scale: Scale factor for font sizes        group_by: Property to use for primary grouping (default: 'molecular_function')        error_threshold: Remove entries with average error above this threshold    Returns:        Matplotlib figure    """    sns.set_context("notebook", font_scale=font_scale)    fig = plt.figure(figsize=(16, 14), dpi=100) # Assign to fig    filtered_structure_indices = list(range(len(structure_ids)))    if domain_dict is not None and any('average_error' in domain_dict.get(sid, {}) for sid in structure_ids):        filtered_structure_indices = [            i for i, sid in enumerate(structure_ids)            if 'average_error' not in domain_dict.get(sid, {}) or            domain_dict.get(sid, {}).get('average_error', 0) <= error_threshold        ]        if len(filtered_structure_indices) < len(structure_ids):            print(f"Filtered out {len(structure_ids) - len(filtered_structure_indices)} structures with average error > {error_threshold}")            structure_ids = [structure_ids[i] for i in filtered_structure_indices]    domain_dict_local = {}    if domain_dict is not None:        for sid in structure_ids:            if sid in domain_dict:                if isinstance(domain_dict[sid], dict) and 'domain' in domain_dict[sid]:                    domain_dict_local[sid] = domain_dict[sid]['domain']                elif isinstance(domain_dict[sid], str):                    domain_dict_local[sid] = domain_dict[sid]                else:                    domain_dict_local[sid] = "Unknown"            else:                domain_dict_local[sid] = "Unknown"    if group_dict is not None:        if domain_dict_local:            sort_key = lambda i: (                group_dict.get(structure_ids[i], "Unknown"),                domain_dict_local.get(structure_ids[i], "Unknown")            )        else:            sort_key = lambda i: group_dict.get(structure_ids[i], "Unknown")        sorted_indices = sorted(range(len(structure_ids)), key=sort_key)        structure_ids_sorted = [structure_ids[i] for i in sorted_indices]        rmsd_matrix = rmsd_df.loc[structure_ids_sorted, structure_ids_sorted].values    else:        structure_ids_sorted = structure_ids        rmsd_matrix = rmsd_df.loc[structure_ids_sorted, structure_ids_sorted].values    max_rmsd = np.nanmax(rmsd_matrix[np.isfinite(rmsd_matrix)]) if np.any(np.isfinite(rmsd_matrix)) else 3.0    rmsd_matrix = np.nan_to_num(rmsd_matrix, nan=0.0, posinf=max_rmsd, neginf=0.0)    rmsd_bounds = RMSD_BOUNDS.copy()    if max_rmsd > rmsd_bounds[-1]:        rmsd_bounds.append(max_rmsd)    norm = BoundaryNorm(rmsd_bounds, RMSD_DISCRETE_CMAP.N)    ax = plt.gca()    im = ax.imshow(rmsd_matrix, cmap=RMSD_DISCRETE_CMAP, norm=norm)    try:        from mpl_toolkits.axes_grid1 import make_axes_locatable        divider = make_axes_locatable(ax)        cax = divider.append_axes("left", size="5%", pad=0.5)        cbar = plt.colorbar(im, cax=cax, ticks=rmsd_bounds)        cbar.set_label('RMSD (Å)', rotation=90, fontsize=14, labelpad=15)        cax.yaxis.set_ticks_position('left')        cax.yaxis.set_label_position('left')    except (ImportError, FileNotFoundError) as e:        print(f"Warning: Could not create colorbar with axes_grid1: {e}")        try:            cbar = fig.colorbar(im, ax=ax, orientation='vertical', pad=0.05, ticks=rmsd_bounds) # Use fig.colorbar            cbar.set_label('RMSD (Å)', rotation=90, fontsize=14, labelpad=15)        except Exception as e2:            print(f"Warning: Could not create alternate colorbar: {e2}")    ax.set_xticks([])    ax.set_yticks([])    ax.set_title('Structural Similarity Matrix (RMSD)', pad=20, fontsize=18, fontweight='bold')    if group_dict is not None:        molecular_functions = [group_dict.get(sid, "Unknown") for sid in structure_ids_sorted]        domains_from_dict = [domain_dict_local.get(sid, "Unknown") for sid in structure_ids_sorted] # Renamed        unique_functions = []        function_sizes = []        current_function = None        count = 0        for func in molecular_functions:            if func != current_function:                if current_function is not None:                    unique_functions.append(current_function)                    function_sizes.append(count)                current_function = func                count = 1            else:                count += 1        if current_function is not None:            unique_functions.append(current_function)            function_sizes.append(count)        function_boundaries = np.cumsum(function_sizes)        for boundary in function_boundaries[:-1]:            ax.axhline(y=boundary - 0.5, color=OPSIN_COLORS['white'], linewidth=2.5)            ax.axvline(x=boundary - 0.5, color=OPSIN_COLORS['white'], linewidth=2.5)        if domain_dict_local:            domain_subgroups = []            start_idx = 0            for func_size, _ in zip(function_sizes, unique_functions): # func_name not used                func_range = list(range(start_idx, start_idx + func_size))                func_domains = [domains_from_dict[i] for i in func_range]                # domain_counts = {} # Not used                last_domain = None                current_subgroup_size = 0                current_subgroup_start = -1                for i_local, domain_val in enumerate(func_domains): # Renamed i to i_local, domain to domain_val                    actual_idx_in_sorted_list = start_idx + i_local                    if domain_val != last_domain:                        if last_domain is not None: # Store previous subgroup                             domain_subgroups.append((last_domain, current_subgroup_start, current_subgroup_size))                        # Start new subgroup                        last_domain = domain_val                        current_subgroup_start = actual_idx_in_sorted_list                        current_subgroup_size = 1                    else:                        current_subgroup_size +=1                if last_domain is not None: # Store the last subgroup of this function block                    domain_subgroups.append((last_domain, current_subgroup_start, current_subgroup_size))                start_idx += func_size            for _, subgroup_start, subgroup_size in domain_subgroups:                end_idx = subgroup_start + subgroup_size                if end_idx < len(structure_ids_sorted) and end_idx not in function_boundaries:                    ax.axhline(y=end_idx - 0.5, color=OPSIN_COLORS['white'], linewidth=1.0, alpha=0.5)                    ax.axvline(x=end_idx - 0.5, color=OPSIN_COLORS['white'], linewidth=1.0, alpha=0.5)        function_color_map = get_group_colors(sorted(list(set(molecular_functions)))) # Use list for robustness        domain_color_map = get_group_colors(sorted(list(set(domains_from_dict))))    # Use list        pos_val = 0 # Renamed pos to pos_val        for func, size in zip(unique_functions, function_sizes):            ax.add_patch(plt.Rectangle(                (pos_val, -0.05 * rmsd_matrix.shape[0]), size, 0.02 * rmsd_matrix.shape[0],                facecolor=function_color_map.get(func, OPSIN_COLORS['gray_light']), # Use .get for safety                edgecolor='none', alpha=0.8,                transform=ax.transData, clip_on=False            ))            pos_val += size        if domain_dict_local:            for domain_val, start_idx, size in domain_subgroups: # Renamed domain to domain_val                ax.add_patch(plt.Rectangle(                    (rmsd_matrix.shape[1], start_idx), 0.02 * rmsd_matrix.shape[1], size,                    facecolor=domain_color_map.get(domain_val, OPSIN_COLORS['gray_light']), # Use .get                    edgecolor='none', alpha=0.8,                    transform=ax.transData, clip_on=False                ))        function_legend_elements = [            plt.Rectangle((0, 0), 1, 1, facecolor=function_color_map.get(func, OPSIN_COLORS['gray_light']),                          edgecolor='none', label=func)            for func in sorted(list(set(molecular_functions)))        ]        domain_legend_elements = [            plt.Rectangle((0, 0), 1, 1, facecolor=domain_color_map.get(domain_val, OPSIN_COLORS['gray_light']),                          edgecolor='none', label=domain_val)            for domain_val in sorted(list(set(domains_from_dict)))        ]        legend_fig_local = plt.figure(figsize=(3, 5)) # Renamed legend_fig        legend_ax = legend_fig_local.add_subplot(111)        legend_ax.axis('off')        leg1 = legend_ax.legend(            handles=function_legend_elements, title="Molecular Function",            loc='upper center', fontsize=12, title_fontsize=14        )        if leg1: leg1.get_frame().set_alpha(0.8) # Check if legend was created        if domain_dict_local and domain_legend_elements: # Check if elements exist            leg2 = legend_ax.legend(                handles=domain_legend_elements, title="Domain",                loc='lower center', fontsize=12, title_fontsize=14            )            if leg2: leg2.get_frame().set_alpha(0.8)            if leg1: legend_ax.add_artist(leg1) # Re-add first legend if second is created        legend_path = 'rmsd_heatmap_legends.png' # Consider making this path configurable        legend_fig_local.savefig(legend_path, dpi=300, bbox_inches='tight')        plt.close(legend_fig_local)        ax.text(0.95, 0.05, "Legends saved separately",                transform=ax.transAxes, ha='right', va='bottom',                fontsize=10, color='black', bbox=dict(facecolor='white', alpha=0.7))    plt.tight_layout()    return fig # Return the figure objectdef create_and_visualize_similarity_tree(rmsd_data, group_dict=None, domain_dict=None,                                         name_dict=None, font_scale=1.0, leaf_font_size=12,                                         group_by='molecular_function',                                         linkage_matrix=None):    """    Create a similarity tree (dendrogram) from the RMSD matrix with consistent colors.    Args:        rmsd_data: RMSD DataFrame (should be pre-filtered)        group_dict: Dictionary mapping structure IDs to molecular function groups        domain_dict: Dictionary mapping structure IDs to domain groups (dict or string)        name_dict: Dictionary mapping structure IDs to display names        font_scale: Scale factor for font sizes        leaf_font_size: Font size for leaf labels        group_by: Property to use for primary coloring (default: 'molecular_function')        linkage_matrix: Pre-calculated linkage matrix (Z) (optional)    Returns:        Tuple: (Matplotlib figure, list of ordered structure IDs)    """    sns.set_context("notebook", font_scale=font_scale)    fig = plt.figure(figsize=(16, 12), dpi=100)    plt.grid(False)    structure_ids = rmsd_data.index.tolist()    rmsd_matrix = rmsd_data.values    N = len(structure_ids)    if rmsd_matrix.shape != (N, N):        raise ValueError(f"RMSD matrix dimensions ({rmsd_matrix.shape}) must match the number of structures ({N}).")    if linkage_matrix is None:        print("DEBUG (Tree): Calculating linkage matrix internally.")        if np.any(~np.isfinite(rmsd_matrix)):            mask = np.isfinite(rmsd_matrix)            max_rmsd = np.max(rmsd_matrix[mask]) if np.any(mask) else 1.0            clean_matrix = np.nan_to_num(rmsd_matrix, nan=0.0, posinf=max_rmsd, neginf=0.0)        else:            clean_matrix = rmsd_matrix.copy()        np.fill_diagonal(clean_matrix, 0.0)        condensed_matrix = squareform(clean_matrix, checks=False)        Z = linkage(condensed_matrix, method='average')    else:        print("DEBUG (Tree): Using provided linkage matrix.")        Z = linkage_matrix    def link_color_func(k):        return OPSIN_COLORS['gray_dark']    ax = plt.gca()    dendro = dendrogram(        Z, ax=ax, labels=None, orientation='right',        link_color_func=link_color_func,        above_threshold_color=OPSIN_COLORS['gray_dark'],        show_leaf_counts=False, no_labels=True    )    ax.tick_params(axis='x', labelsize=12)    ax.tick_params(axis='y', labelcolor='none')    function_dict = {}    domain_dict_local = {}    if group_dict is not None:        for sid in structure_ids:            function_dict[sid] = str(group_dict.get(sid, "Unknown"))    else:        function_dict = {sid: "Unknown" for sid in structure_ids}    if domain_dict is not None:        for sid in structure_ids:            domain_info = domain_dict.get(sid, "Unknown")            if isinstance(domain_info, dict):                domain_dict_local[sid] = str(domain_info.get('domain', "Unknown"))            else:                domain_dict_local[sid] = str(domain_info)    else:        domain_dict_local = {sid: "Unknown" for sid in structure_ids}    unique_functions = sorted(list(set(function_dict.values())))    unique_domains = sorted(list(set(domain_dict_local.values())))    function_color_map = get_group_colors(unique_functions)    domain_color_map = get_group_colors(unique_domains)    leaf_indices = dendro['leaves']    ordered_structure_ids = [structure_ids[i] for i in leaf_indices]    for i, leaf_idx in enumerate(leaf_indices):        if leaf_idx < len(structure_ids):            sid = structure_ids[leaf_idx]            function = function_dict.get(sid, "Unknown")            domain_val = domain_dict_local.get(sid, "Unknown") # Renamed domain            y_coord = (i * 10) + 5 # Visual y-coordinate based on leaf index            rect_height = 7 # Visual height of the color patch            x_limit_max = ax.get_xlim()[1] # Furthest x-point of dendrogram            function_rect_width = 0.07 * x_limit_max # Width of function color patch            function_rect = plt.Rectangle(                (x_limit_max, y_coord - rect_height / 2),                function_rect_width, rect_height,                facecolor=function_color_map.get(function, OPSIN_COLORS['gray_light']),                edgecolor='none', alpha=0.8, clip_on=False            )            ax.add_patch(function_rect)            domain_rect_width = 0.04 * x_limit_max # Width of domain color patch            domain_rect = plt.Rectangle(                (x_limit_max + function_rect_width + 0.01 * x_limit_max, y_coord - rect_height / 2),                domain_rect_width, rect_height,                facecolor=domain_color_map.get(domain_val, OPSIN_COLORS['gray_light']),                edgecolor='none', alpha=0.8, clip_on=False            )            ax.add_patch(domain_rect)    function_legend_elements = [        plt.Rectangle((0, 0), 1, 1, facecolor=function_color_map.get(func, OPSIN_COLORS['gray_light']),                      edgecolor='none', label=func)        for func in unique_functions if func != "Unknown" # Exclude unknown from legend if desired    ]    domain_legend_elements = [        plt.Rectangle((0, 0), 1, 1, facecolor=domain_color_map.get(domain_val, OPSIN_COLORS['gray_light']),                      edgecolor='none', label=domain_val)        for domain_val in unique_domains if domain_val != "Unknown"    ]    leg1 = ax.legend(        handles=function_legend_elements, title="Molecular Function",        bbox_to_anchor=(1.35, 0.7), loc='center left',        fontsize=leaf_font_size, title_fontsize=leaf_font_size + 2    )    if leg1: leg1.get_frame().set_alpha(0.8)    if leg1: ax.add_artist(leg1)    if domain_dict_local and domain_legend_elements:        leg2 = ax.legend(            handles=domain_legend_elements, title="Domain",            bbox_to_anchor=(1.35, 0.3), loc='center left',            fontsize=leaf_font_size, title_fontsize=leaf_font_size + 2        )        if leg2: leg2.get_frame().set_alpha(0.8)        if leg2: ax.add_artist(leg2)    max_dist_for_norm = np.max(Z[:, 2]) if Z is not None and Z.shape[0] > 0 else 3.0    norm = plt.Normalize(0, min(3.0, max_dist_for_norm)) # Cap norm at 3.0 for consistency    # Ensure RMSD_COMPACT_CMAP is a valid colormap object or string    try:        cmap = plt.cm.get_cmap(RMSD_COMPACT_CMAP)    except ValueError:        print(f"Warning: Colormap '{RMSD_COMPACT_CMAP}' not found. Using 'viridis'.")        cmap = plt.cm.get_cmap('viridis')    try:        from mpl_toolkits.axes_grid1 import make_axes_locatable        divider = make_axes_locatable(ax)        cax = divider.append_axes("left", size="5%", pad=0.5)        cb = plt.colorbar(plt.cm.ScalarMappable(norm=norm, cmap=cmap), cax=cax)        cb.set_label('RMSD (Å)', rotation=90, fontsize=12, labelpad=15)        cax.yaxis.set_ticks_position('left')        cax.yaxis.set_label_position('left')    except Exception as e:        print(f"Warning: Could not create colorbar for similarity tree with axes_grid1: {e}")        try:            cb = fig.colorbar(plt.cm.ScalarMappable(norm=norm, cmap=cmap),                              ax=ax, orientation='vertical', pad=0.05, aspect=40)            cb.set_label('RMSD (Å)', rotation=90, fontsize=12, labelpad=15)        except Exception as e2:            print(f"Warning: Could not create alternate colorbar for similarity tree: {e2}")    ax.set_title('Structural Similarity Tree', fontsize=18, pad=20, fontweight='bold')    ax.set_xlabel('Distance (RMSD, Å)', fontsize=14)    ax.spines['top'].set_visible(False)    ax.spines['right'].set_visible(False)    ax.spines['left'].set_visible(False) # Keep left spine for x-axis label context    fig.tight_layout(rect=[0.05, 0, 0.80, 1]) # Adjust right margin for legends    return fig, ordered_structure_idsdef visualize_rmsd_matrix_improved(rmsd_df, group_dict=None, name_dict=None,                                   output_file=None, figsize=(14, 12),                                   domain_dict=None, linkage_matrix=None):    """    Improved visualization of RMSD matrix using a pre-calculated clustering.    Uses the global color scheme for consistent visualization.    Args:        rmsd_df: DataFrame with RMSD values (should be pre-filtered)        group_dict: Dictionary mapping structure ID to group/type (for y-axis)        name_dict: Dictionary mapping structure ID to display name        output_file: Optional file path to save the figure        figsize: Figure size        domain_dict: Dictionary mapping structure ID to domain (for x-axis, dict or string)        linkage_matrix: Pre-calculated linkage matrix (Z) REQUIRED    Returns:        Seaborn clustermap object or None if error    """    pdb_list = rmsd_df.index.tolist()    if linkage_matrix is None:        print("ERROR (Heatmap): Linkage matrix (Z) is required for visualize_rmsd_matrix_improved.")        return None    if len(pdb_list) < 2:        print("Not enough structures to create RMSD matrix visualization.")        return None    try:        # Get order from linkage matrix for color assignments        dendrogram_out = dendrogram(linkage_matrix, no_plot=True)        ordered_indices = dendrogram_out['leaves']        ordered_ids = [pdb_list[i] for i in ordered_indices] # IDs in the order Z will produce        print(f"DEBUG (Heatmap): Order derived from provided Z: {len(ordered_ids)} structures for color mapping.")    except Exception as e:        print(f"ERROR (Heatmap): Could not derive order from provided linkage matrix: {e}. Using original order for colors.")        ordered_ids = pdb_list # Fallback    # Prepare row_colors Series for clustermap (must match the order Z will produce)    row_colors_data = None    row_color_map_legend = {}    if group_dict:        # Ensure groups are strings and get unique ones from the ordered_ids        unique_groups = sorted(list(set(str(group_dict.get(id_val, 'Unknown')) for id_val in ordered_ids)))        row_color_map_legend = get_group_colors(unique_groups)        # Create a list of colors in the order clustermap will use (derived from Z)        colors_for_series = [row_color_map_legend.get(str(group_dict.get(id_val, 'Unknown')), OPSIN_COLORS['gray_light']) for id_val in ordered_ids]        # Create a Series with the original PDB IDs as index, but colors ordered by Z's output.        # This is tricky. Clustermap reorders the input DF based on linkage.        # row_colors needs to be a Series whose index matches the input DF's index.        # Clustermap will then reorder this Series internally.        row_colors_list_original_order = [row_color_map_legend.get(str(group_dict.get(id_val, 'Unknown')), OPSIN_COLORS['gray_light']) for id_val in rmsd_df.index]        row_colors_data = pd.Series(row_colors_list_original_order, index=rmsd_df.index, name='Function')    col_colors_data = None    col_color_map_legend = {}    if domain_dict:        domain_values_ordered = []        for id_val in ordered_ids: # Use Z-derived order for creating unique domain list for legend            domain_info = domain_dict.get(id_val, "Unknown")            if isinstance(domain_info, dict):                domain_values_ordered.append(str(domain_info.get('domain', 'Unknown')))            else:                domain_values_ordered.append(str(domain_info))        unique_domains = sorted(list(set(domain_values_ordered)))        col_color_map_legend = get_group_colors(unique_domains)        # Colors for Series, in original DF order        col_colors_list_original_order = []        for id_val in rmsd_df.index:            domain_info = domain_dict.get(id_val, "Unknown")            domain_str = str(domain_info.get('domain', 'Unknown')) if isinstance(domain_info, dict) else str(domain_info)            col_colors_list_original_order.append(col_color_map_legend.get(domain_str, OPSIN_COLORS['gray_light']))        col_colors_data = pd.Series(col_colors_list_original_order, index=rmsd_df.index, name='Domain')    elif group_dict and row_colors_data is not None : # If no domain_dict, use group_dict for columns too        col_colors_data = row_colors_data.rename('Group') # Use same colors, different label        col_color_map_legend = row_color_map_legend    print(f"DEBUG (Heatmap): Plotting clustermap with {rmsd_df.shape} matrix and provided Z.")    try:        g = sns.clustermap(            rmsd_df,  # Original (pre-filtered but not Z-ordered) DataFrame            row_linkage=linkage_matrix,            col_linkage=linkage_matrix,            row_colors=row_colors_data, # Series indexed by rmsd_df.index            col_colors=col_colors_data, # Series indexed by rmsd_df.index            xticklabels=False, yticklabels=False,            figsize=figsize, cmap=RMSD_COMPACT_CMAP, # Use the global compact cmap            vmin=0, vmax=3.0,            cbar_kws={'label': 'RMSD (Å)'},            dendrogram_ratio=(.15, .15) # Adjust dendrogram size        )        # Add Legends to the clustermap figure (g.fig)        handles = []        labels = []        legend_title_parts = []        if row_colors_data is not None and row_color_map_legend:            handles.extend([Patch(color=color, label=group) for group, color in sorted(row_color_map_legend.items()) if group != "Unknown"])            labels.extend([group for group, color in sorted(row_color_map_legend.items()) if group != "Unknown"])            if row_colors_data.name: legend_title_parts.append(row_colors_data.name)        if col_colors_data is not None and col_color_map_legend and \           (row_colors_data is None or col_colors_data.name != row_colors_data.name): # Add only if different from row            if handles: # Add a visual separator if both legends are present                handles.append(Patch(color='white', label="")) # Invisible separator                labels.append("")            handles.extend([Patch(color=color, label=domain) for domain, color in sorted(col_color_map_legend.items()) if domain != "Unknown"])            labels.extend([domain for domain, color in sorted(col_color_map_legend.items()) if domain != "Unknown"])            if col_colors_data.name: legend_title_parts.append(col_colors_data.name)        final_legend_title = " / ".join(legend_title_parts) if legend_title_parts else "Legend"        if handles:            try:                # Position legend carefully within the figure created by clustermap                g.fig.legend(handles, labels, title=final_legend_title,                             loc='lower left', bbox_to_anchor=(0.01, 0.01), # Example position                             fontsize=8, title_fontsize=10, frameon=True, ncol=1)                # May need to adjust g.fig.subplots_adjust or tight_layout on g.fig                g.fig.tight_layout(rect=[0, 0, 0.9, 0.95]) # Adjust rect to make space, e.g. for legend on right            except Exception as leg_e:                print(f"Warning (Heatmap): Could not add legend: {leg_e}")        g.fig.suptitle("Structure Similarity Matrix (RMSD)", fontsize=16, y=0.98)        if output_file:            print(f"DEBUG (Heatmap): Saving clustermap figure to {output_file}")            g.fig.savefig(output_file, dpi=300, bbox_inches='tight')            print(f"Saved heatmap figure to {os.path.basename(str(output_file))}")        return g    except Exception as e:        print(f"ERROR (Heatmap): Failed to generate clustermap: {e}")        import traceback        traceback.print_exc()        return Nonedef visualize_binding_pocket(structure, residue_ids, retinal=None, highlight_residues=None,                             distance_cutoff=4.0, figsize=(800, 600)):    """    Create an interactive 3D visualization of a binding pocket with retinal.    Args:        structure: DataFrame with structure coordinates        residue_ids: List of residue IDs to include in visualization        retinal: DataFrame with retinal coordinates (optional)        highlight_residues: Dict mapping residue IDs to highlight colors        distance_cutoff: Distance cutoff for showing atom contacts        figsize: Figure size tuple (width, height)    Returns:        Plotly figure object    """    pocket_df = structure[structure['auth_seq_id'].isin(residue_ids)]    traces = []    for res_id, res_df in pocket_df.groupby('auth_seq_id'):        color = OPSIN_COLORS['gray_dark']        if highlight_residues and res_id in highlight_residues:            color = highlight_residues[res_id]        elif 'helix_num' in res_df.columns and not res_df['helix_num'].isna().all():            helix_num = res_df['helix_num'].iloc[0]            if pd.notna(helix_num) and int(helix_num) in HELIX_COLORS: # Check for NaN and ensure int                color = HELIX_COLORS[int(helix_num)]        res_type = '?'        if 'res_name3l' in res_df.columns and pd.notna(res_df['res_name3l'].iloc[0]):            res_type = res_df['res_name3l'].iloc[0]        elif 'res_name1l' in res_df.columns and pd.notna(res_df['res_name1l'].iloc[0]):            res_type = res_df['res_name1l'].iloc[0]        traces.append(go.Scatter3d(            x=res_df['x'], y=res_df['y'], z=res_df['z'],            mode='markers',            marker=dict(size=5, color=color, opacity=0.8),            text=[f"{res_type}{res_id} - {atom}" for atom in res_df['res_atom_name']],            hoverinfo='text', name=f"{res_type}{res_id}"        ))    if retinal is not None and not retinal.empty:        retinal_color_key = 'retinal' if 'retinal' in HELIX_COLORS else 7 # Fallback if 'retinal' key missing        retinal_plot_color = HELIX_COLORS.get(retinal_color_key, OPSIN_COLORS['yellow'])        traces.append(go.Scatter3d(            x=retinal['x'], y=retinal['y'], z=retinal['z'],            mode='markers',            marker=dict(size=6, color=retinal_plot_color, symbol='diamond', opacity=0.9),            text=[f"RET - {atom}" for atom in retinal['res_atom_name']],            hoverinfo='text', name="Retinal"        ))        if distance_cutoff > 0 and not pocket_df.empty: # Ensure pocket_df is not empty for cdist            ret_coords = retinal[['x', 'y', 'z']].values            pocket_coords = pocket_df[['x', 'y', 'z']].values            distances = cdist(ret_coords, pocket_coords)            contacts = np.where(distances < distance_cutoff)            if len(contacts[0]) > 0:                contact_x, contact_y, contact_z = [], [], []                for ret_idx, pocket_row_idx in zip(contacts[0], contacts[1]): # pocket_idx is row index in pocket_coords                    rx, ry, rz = ret_coords[ret_idx]                    px, py, pz = pocket_coords[pocket_row_idx] # Use pocket_row_idx                    contact_x.extend([rx, px, None])                    contact_y.extend([ry, py, None])                    contact_z.extend([rz, pz, None])                traces.append(go.Scatter3d(                    x=contact_x, y=contact_y, z=contact_z,                    mode='lines',                    line=dict(color=OPSIN_COLORS['yellow'], width=2, dash='dot'),                    opacity=0.6, hoverinfo='none', name="Contacts", showlegend=True                ))    fig = go.Figure(data=traces)    fig.update_layout(        title="Binding Pocket Visualization",        scene=dict(            xaxis_title='X', yaxis_title='Y', zaxis_title='Z',            aspectmode='data',            xaxis=dict(showbackground=True, backgroundcolor=OPSIN_COLORS['white']),            yaxis=dict(showbackground=True, backgroundcolor=OPSIN_COLORS['white']),            zaxis=dict(showbackground=True, backgroundcolor=OPSIN_COLORS['white'])        ),        width=figsize[0], height=figsize[1],        margin=dict(l=0, r=0, b=0, t=40),        legend=dict(x=0.01, y=0.99, bgcolor=OPSIN_COLORS['white'], bordercolor=OPSIN_COLORS['gray_light'])    )    return figdef plot_distances_with_std(distance_table, title="Distance to Retinal by Position", figsize=(18, 10), use_ca=False):    """    Plot the average distances with standard deviation error bars for TM residues only (helices 1-7).    Args:        distance_table: DataFrame with distances        title: Title for the plot        figsize: Figure size tuple        use_ca: Whether to label as CA distances or all-atom distances    Returns:        Matplotlib figure    """    if distance_table.empty:        fig, ax = plt.subplots(figsize=figsize)        ax.text(0.5, 0.5, "No data available", ha='center', va='center', transform=ax.transAxes, fontsize=14)        ax.set_title(title, fontsize=16)        return fig    tm_positions = []    for pos in distance_table.columns:        pos_str = str(pos)        if '.' in pos_str:            parts = pos_str.split('.')            if len(parts) == 2 and parts[0].isdigit() and 1 <= int(parts[0]) <= 7 and parts[1].replace('.','',1).isdigit():                tm_positions.append(pos)    if not tm_positions:        fig, ax = plt.subplots(figsize=figsize)        ax.text(0.5, 0.5, "No TM residues found in data", ha='center', va='center', transform=ax.transAxes, fontsize=14)        ax.set_title(title, fontsize=16)        return fig    tm_distance_table = distance_table[tm_positions]    mean_distances = tm_distance_table.mean(skipna=True)    std_distances = tm_distance_table.std(skipna=True)    fig, ax = plt.subplots(figsize=figsize)    def custom_sort_key(pos_val): # Renamed pos to pos_val        pos_str = str(pos_val)        parts = pos_str.split('.') # Assumes N.XX format due to tm_positions filter        return (int(parts[0]), float(parts[1]))    positions = sorted(mean_distances.index, key=custom_sort_key)    x_vals = np.arange(len(positions)) # Use np.arange for x_vals    y_vals = [mean_distances[pos] for pos in positions]    # Ensure err_vals are non-negative and handle NaNs from std_distances    err_vals = [max(0, std_distances.get(pos, 0)) if pd.notna(std_distances.get(pos)) else 0 for pos in positions]    point_colors = []    for pos_val in positions: # Renamed pos to pos_val        helix_num_str = str(pos_val).split('.')[0]        helix_num = int(helix_num_str) if helix_num_str.isdigit() else 0 # Fallback for safety        point_colors.append(HELIX_COLORS.get(helix_num, OPSIN_COLORS['gray_dark']))    for i, (x, y, color) in enumerate(zip(x_vals, y_vals, point_colors)):        ax.plot(x, y, 'o', color=color, markersize=8)    for i, (x, y, err, color) in enumerate(zip(x_vals, y_vals, err_vals, point_colors)):        ax.errorbar(x, y, yerr=err, fmt='none', ecolor=color, alpha=0.8, capsize=5,                    elinewidth=1.5, capthick=1.5)    current_helix = None    helix_x_vals = []    helix_y_vals = []    helix_color = None    for i, pos_val in enumerate(positions): # Renamed pos to pos_val        pos_str = str(pos_val)        helix_num_str = pos_str.split('.')[0]        helix_num = int(helix_num_str) if helix_num_str.isdigit() else 0        if current_helix is None: # First point            current_helix = helix_num            helix_color = HELIX_COLORS.get(helix_num, OPSIN_COLORS['gray_dark'])        if helix_num == current_helix:            helix_x_vals.append(x_vals[i])            helix_y_vals.append(y_vals[i])        else: # New helix starts            if helix_x_vals: # Plot previous helix line if it has points                 ax.plot(helix_x_vals, helix_y_vals, '-', color=helix_color, linewidth=2.0, alpha=0.7)            # Reset for new helix            current_helix = helix_num            helix_color = HELIX_COLORS.get(helix_num, OPSIN_COLORS['gray_dark'])            helix_x_vals = [x_vals[i]]            helix_y_vals = [y_vals[i]]    if helix_x_vals: # Plot the last helix segment        ax.plot(helix_x_vals, helix_y_vals, '-', color=helix_color, linewidth=2.0, alpha=0.7)    ax.set_xticks(x_vals)    ax.set_xticklabels(positions, rotation=90, fontsize=8)    max_y_for_text = (max(y_vals) if y_vals else 10) # Default if y_vals is empty    for i, pos_val in enumerate(positions): # Renamed pos to pos_val        pos_str = str(pos_val)        if pos_str.endswith('.50'): # Check for X.50            helix_str = pos_str.split('.')[0]            if helix_str.isdigit() and int(helix_str) in HELIX_COLORS:                color = HELIX_COLORS[int(helix_str)]                ax.axvline(x=i, color=color, linestyle='--', alpha=0.6, linewidth=1.5)                ax.text(i, max_y_for_text * 1.05, f"H{helix_str}",                        ha='center', va='bottom', fontsize=12, color=color, fontweight='bold')    ax.grid(True, alpha=0.3)    ax.set_xlabel('Position (GRN Format)', fontsize=14)    ax.set_ylabel('Distance to Retinal (Å)', fontsize=14)    if y_vals: # Ensure y_vals is not empty        valid_y_err = [e for e in err_vals if pd.notna(e) and e is not None] # Filter out None/NaN from err_vals        max_err = max(valid_y_err) if valid_y_err else 0        max_y_val = max(y_vals) + max_err        ax.set_ylim(0, max_y_val * 1.1 if max_y_val > 0 else 10) # Ensure positive upper limit    else:        ax.set_ylim(0, 10)    subtitle = "CA Atoms" if use_ca else "All Atoms"    ax.set_title(f"{title} ({subtitle})", fontsize=18)    import matplotlib.patches as mpatches # Local import for safety    legend_handles = []    for helix_num_iter in range(1, 8): # Renamed helix_num        color = HELIX_COLORS.get(helix_num_iter)        if color is not None: # Ensure color exists             legend_handles.append(mpatches.Patch(color=color, label=f"Helix {helix_num_iter}"))    if legend_handles: # Only show legend if there are handles        ax.legend(handles=legend_handles, loc='upper right', ncol=2, fontsize=10, frameon=True, framealpha=0.8)    plt.tight_layout()    return figdef plot_helix_logo_plots(residue_table, figsize=(20, 5)):    """    Create sequence logo plots for positions around X.50 for each of the 7 transmembrane helices.    Shows amino acid composition variability for each position.    Args:        residue_table: DataFrame with residue information (ca_residue_table_grn)        figsize: Figure size tuple (width, height)    Returns:        Matplotlib figure with 7 logo subplots    """    from collections import Counter # Local import    if residue_table is None or residue_table.empty:        fig, ax = plt.subplots(figsize=(8, 5))        ax.text(0.5, 0.5, "No data available", ha='center', va='center', transform=ax.transAxes, fontsize=14)        return fig    window_size = 4    fig, axes = plt.subplots(1, 7, figsize=figsize, sharey=True)    valid_columns = []    for col in residue_table.columns:        col_str = str(col)        if '.' in col_str:            try:                helix_num_str = col_str.split('.')[0]                if helix_num_str.isdigit() and 1 <= int(helix_num_str) <= 7:                    valid_columns.append(col)            except ValueError:                continue    filtered_table = residue_table[valid_columns]    if filtered_table.empty: # If no valid columns after filtering        for i in range(7):            axes[i].text(0.5, 0.5, f"No valid TM data for Helix {i+1}", ha='center', va='center', transform=axes[i].transAxes)        plt.tight_layout()        return fig    for helix_num in range(1, 8):        ax = axes[helix_num - 1]        pivot_pos_str = f"{helix_num}.50" # Renamed pivot_pos        helix_positions = [col for col in filtered_table.columns if str(col).startswith(f"{helix_num}.")]        def position_sort_key(pos_val): # Renamed pos            return float(str(pos_val).split('.')[1])        helix_positions = sorted(helix_positions, key=position_sort_key)        actual_pivot_pos = pivot_pos_str # Store the actual pivot used (might change)        try:            pivot_idx = helix_positions.index(pivot_pos_str)        except ValueError:            closest_positions = sorted([(abs(position_sort_key(pos_val) - 50.0), pos_val) for pos_val in helix_positions])            if closest_positions:                actual_pivot_pos = closest_positions[0][1]                pivot_idx = helix_positions.index(actual_pivot_pos)                print(f"[WARNING] Position {pivot_pos_str} not found for Helix {helix_num}, using {actual_pivot_pos} as pivot.")            else:                ax.text(0.5, 0.5, f"No data for Helix {helix_num}", ha='center', va='center', transform=ax.transAxes)                continue        start_idx = max(0, pivot_idx - window_size)        end_idx = min(len(helix_positions), pivot_idx + window_size + 1)        window_positions = helix_positions[start_idx:end_idx]        amino_acids = 'ACDEFGHIKLMNPQRSTVWY'        # Ensure index is string for .at access if window_positions are strings        logo_df_index = [str(wp) for wp in window_positions]        logo_df = pd.DataFrame(0.0, index=logo_df_index, columns=list(amino_acids))        for i, pos_val_str_win in enumerate(window_positions): # Renamed pos to pos_val_str_win            aa_values = []            if pos_val_str_win in filtered_table.columns: # Check if position exists                for cell in filtered_table[pos_val_str_win].values:                    if pd.isna(cell) or cell == '-': continue                    if isinstance(cell, str) and len(cell) > 0:                        aa = cell[0].upper() # Ensure uppercase                        if aa in amino_acids: aa_values.append(aa)            if aa_values:                aa_counter = Counter(aa_values)                total = sum(aa_counter.values())                if total > 0:                    freq_dict = {aa: count / total for aa, count in aa_counter.items()}                    # Normalization to sum to 1.0 (optional, logomaker handles this)                    # sum_freqs = sum(freq_dict.values())                    # if sum_freqs > 0 and abs(sum_freqs - 1.0) > 1e-6:                    #     freq_dict = {aa: freq / sum_freqs for aa, freq in freq_dict.items()}                    for aa, freq in freq_dict.items():                        logo_df.at[str(pos_val_str_win), aa] = freq # Use string index            else: # No AA data for this position in window                 pass # logo_df row will remain all zeros        position_labels = []        pivot_num_val = float(str(actual_pivot_pos).split('.')[1]) # Renamed pivot_value        for pos_val_str_win in window_positions:            pos_num_val = float(str(pos_val_str_win).split('.')[1]) # Renamed pos_value            offset = int(pos_num_val - pivot_num_val)            position_labels.append(offset)        # Reset index of logo_df to simple range for logomaker if it expects integer index        logo_df_for_plot = logo_df.reset_index(drop=True)        if not logo_df_for_plot.empty and logo_df_for_plot.sum().sum() > 0:            try:                lm_logo = logomaker.Logo(logo_df_for_plot, ax=ax, color_scheme='chemistry') # Renamed logo                ax.set_title(f"Helix {helix_num}", color=HELIX_COLORS.get(helix_num, 'black'), fontweight='bold')                ax.set_xlabel("Offset from X.50", fontsize=10)                ax.set_xticks(range(len(window_positions)))                ax.set_xticklabels(position_labels, fontsize=9)                try: # Highlight X.50                    # Find index of actual_pivot_pos in window_positions for axvline                    x50_plot_idx = window_positions.index(actual_pivot_pos)                    ax.axvline(x=x50_plot_idx, color=HELIX_COLORS.get(helix_num, 'gray'), linestyle='--', alpha=0.5)                except ValueError: pass # Pivot not in window (should not happen with logic)                for i_plot, _ in enumerate(window_positions): # Renamed i, pos                    # Use logo_df_for_plot for max_freq and idxmax                    if i_plot < len(logo_df_for_plot): # Ensure index is within bounds                        max_freq = logo_df_for_plot.loc[i_plot].max()                        if max_freq > 0.8: # Highly conserved                            max_aa = logo_df_for_plot.loc[i_plot].idxmax()                            ax.text(i_plot, -0.1 * ax.get_ylim()[1], max_aa, ha='center', fontweight='bold', fontsize=12) # Adjusted y position            except Exception as e_logo:                 ax.text(0.5, 0.5, f"Logo error: {e_logo}", ha='center', va='center', transform=ax.transAxes, fontsize=8)        else:            ax.text(0.5, 0.5, f"No AA data for Helix {helix_num} window", ha='center', va='center', transform=ax.transAxes)    for ax_iter in axes: # Renamed ax        ax_iter.set_ylim(0, 2) # Max 2 bits for information content    axes[0].set_ylabel("Information Content (bits)", fontsize=12)    plt.suptitle("Conserved Amino Acids around Position X.50 in Transmembrane Helices", fontsize=14, y=0.98)    plt.tight_layout(rect=[0, 0.03, 1, 0.95]) # Adjust layout    return figdef plot_average_distances_by_helix(distance_table, use_ca=True):    """    Plot the average distances per position, grouped by helix with consistent helix colors.    Handles both dot notation (1.50) and x notation (1x50) GRN formats.    Args:        distance_table: DataFrame with distances        use_ca: Boolean indicating whether the distances are from CA atoms (True) or sidechains (False)    Returns:        Matplotlib figure    """    if distance_table.empty:        fig, ax = plt.subplots(figsize=(14, 8))        ax.text(0.5, 0.5, "No distance data available", ha='center', va='center', transform=ax.transAxes)        return fig    mean_distances = distance_table.mean(skipna=True)    # Ensure index is string for startswith    tm_distances = mean_distances[        ~mean_distances.index.astype(str).str.startswith('L.') &        ~mean_distances.index.astype(str).str.startswith('n.') &        ~mean_distances.index.astype(str).str.startswith('c.')    ]    plot_data = []    for position, distance in tm_distances.items():        position_str = str(position)        if 'x' in position_str:            try:                helix_str, pos_val_str = position_str.split('x')                if helix_str.isdigit() and pos_val_str.replace('.', '', 1).isdigit():                    plot_data.append({'Helix': helix_str, 'Position': float(pos_val_str), 'Distance (Å)': distance})            except ValueError: continue # Skip malformed 'x'        elif '.' in position_str:            parts = position_str.split('.')            if len(parts) == 2 and parts[0].isdigit() and parts[1].replace('.', '', 1).isdigit():                plot_data.append({'Helix': parts[0], 'Position': float(parts[1]), 'Distance (Å)': distance})    if not plot_data:        fig, ax = plt.subplots(figsize=(14, 8))        ax.text(0.5, 0.5, "No valid TM helix positions found in the data",                horizontalalignment='center', verticalalignment='center',                transform=ax.transAxes, fontsize=14)        plt.tight_layout()        return fig    plot_df = pd.DataFrame(plot_data)    fig, ax = plt.subplots(figsize=(14, 8))    # Ensure Helix column is string for consistent lookup in HELIX_COLORS_STR    plot_df['Helix'] = plot_df['Helix'].astype(str)    for helix_val, group in plot_df.groupby('Helix'):        sorted_group = group.sort_values('Position')        color = HELIX_COLORS_STR.get(helix_val, OPSIN_COLORS['gray_dark']) # helix_val is already string        ax.plot(sorted_group['Position'], sorted_group['Distance (Å)'],                marker='o', linestyle='-', label=f'Helix {helix_val}',                color=color, linewidth=2)    ax.set_xlabel('Position Number', fontsize=12)    ax.set_ylabel('Average Distance to Retinal (Å)', fontsize=12)    distance_type = "Cα Atoms" if use_ca else "Sidechains"    ax.set_title(f'Average Distance to Retinal by Residue Position ({distance_type})', fontsize=14)    # Get unique helix numbers that are digits for axvline    numeric_helices_in_plot = [h for h in plot_df['Helix'].unique() if h.isdigit()]    for helix_str_val in sorted(numeric_helices_in_plot, key=int): # Sort numerically        helix_int_val = int(helix_str_val)        if helix_int_val in HELIX_COLORS:            ax.axvline(x=50, color=HELIX_COLORS[helix_int_val], linestyle='--', alpha=0.3)    ax.legend(bbox_to_anchor=(1.05, 1), loc='upper left', fontsize=10)    ax.grid(True, linestyle='--', alpha=0.7)    current_ylim = ax.get_ylim()    if current_ylim[1] > current_ylim[0]: # Check if ylim is valid before using it        ax.text(50, current_ylim[1] * 0.95, "X.50",                ha='center', va='top', fontsize=10,                bbox=dict(facecolor='white', alpha=0.8, edgecolor='gray'))    plt.tight_layout(rect=[0, 0, 0.85, 1]) # Adjust for legend    return figdef plot_distance_heatmap(distance_table):    """    Create a heatmap of average distances ordered by helix and position using the consistent color scheme.    Handles both dot notation (1.50) and x notation (1x50) GRN formats.    Args:        distance_table: DataFrame with distances    Returns:        Matplotlib figure    """    if distance_table.empty:        fig, ax = plt.subplots(figsize=(16, 8))        ax.text(0.5, 0.5, "No distance data to plot heatmap", ha='center', va='center', transform=ax.transAxes)        return fig    mean_distances = distance_table.mean(skipna=True)    tm_distances = mean_distances[        ~mean_distances.index.astype(str).str.startswith('L.') &        ~mean_distances.index.astype(str).str.startswith('n.') &        ~mean_distances.index.astype(str).str.startswith('c.')    ]    plot_data = []    for position, distance in tm_distances.items():        position_str = str(position)        if 'x' in position_str:            try:                helix_str, pos_val_str = position_str.split('x')                if helix_str.isdigit() and pos_val_str.replace('.', '', 1).isdigit():                    plot_data.append({'Helix': int(helix_str), 'Position': float(pos_val_str), 'Distance (Å)': distance})            except ValueError: continue        elif '.' in position_str:            parts = position_str.split('.')            if len(parts) == 2 and parts[0].isdigit() and parts[1].replace('.', '', 1).isdigit():                 plot_data.append({'Helix': int(parts[0]), 'Position': float(parts[1]), 'Distance (Å)': distance})    if not plot_data:        fig, ax = plt.subplots(figsize=(16, 8))        ax.text(0.5, 0.5, "No valid TM helix positions found for heatmap",                horizontalalignment='center', verticalalignment='center',                transform=ax.transAxes, fontsize=14)        plt.tight_layout()        return fig    plot_df = pd.DataFrame(plot_data)    # Sort by Helix first, then Position for pivot table ordering    plot_df = plot_df.sort_values(by=['Helix', 'Position'])    pivot_df = plot_df.pivot(index='Helix', columns='Position', values='Distance (Å)')    fig, ax = plt.subplots(figsize=(16, 8))    try:        if isinstance(RMSD_CMAP, str):            reversed_cmap = plt.cm.get_cmap(RMSD_CMAP).reversed()        elif hasattr(RMSD_CMAP, 'reversed'):             reversed_cmap = RMSD_CMAP.reversed()        else: # Manual reversal for ListedColormap            reversed_cmap = ListedColormap(RMSD_CMAP.colors[::-1])    except Exception as e_cmap:        print(f"Warning: Could not reverse RMSD_CMAP ({RMSD_CMAP}): {e_cmap}. Using 'magma_r'.")        reversed_cmap = "magma_r"    vmin_val = min(3.0, pivot_df.min().min()) if not pivot_df.empty and pd.notna(pivot_df.min().min()) else 0    vmax_val = min(20.0, pivot_df.max().max()) if not pivot_df.empty and pd.notna(pivot_df.max().max()) else 10    sns.heatmap(pivot_df, cmap=reversed_cmap, ax=ax,                cbar_kws={'label': 'Distance to Retinal (Å)'},                vmin=vmin_val, vmax=vmax_val, annot=False) # Annot usually too dense    ax.set_title('Distance to Retinal by Position', fontsize=14)    ax.set_xlabel('Position Number', fontsize=12)    ax.set_ylabel('Helix', fontsize=12)    if 50.0 in pivot_df.columns: # Ensure 50.0 is float if columns are floats        try:            col_idx_50 = pivot_df.columns.get_loc(50.0)            ax.axvline(x=col_idx_50 + 0.5,                     color=OPSIN_COLORS['white'], linestyle='--', alpha=0.7, linewidth=1.5)        except KeyError:            print("Note: Position 50.0 not found in heatmap columns for highlighting.")    # Customize y-tick labels with helix colors if numeric    ax.set_yticks(np.arange(len(pivot_df.index)) + 0.5) # Set ticks before labels    ax.set_yticklabels(pivot_df.index, fontweight='bold')    for i, tick_label in enumerate(ax.get_yticklabels()):        helix_num_val = pivot_df.index[i] # helix_num_val is already int from pivot        if isinstance(helix_num_val, (int, float)) and int(helix_num_val) in HELIX_COLORS:            tick_label.set_color(HELIX_COLORS[int(helix_num_val)])    plt.tight_layout()    return figdef print_residue_composition(composition_dict, highlight_threshold=20.0):    """    Pretty-print the residue composition results with highlighting of significant values.    Args:        composition_dict: Dictionary from analyze_residue_composition        highlight_threshold: Percentage threshold above which to highlight residues    """    print("\nResidue Composition at Key Positions:")    print("=====================================")    for position, composition in composition_dict.items():        print(f"\nPosition {position}:")        print("-" * (len(str(position)) + 10))        if isinstance(composition, dict) and 'error' in composition:            print(f"  {composition['error']}")            continue        processed = False        if isinstance(composition, dict):            target_freq_dict = None            if 'frequencies' in composition and isinstance(composition['frequencies'], dict):                target_freq_dict = composition['frequencies']            elif 'sorted' in composition and isinstance(composition['sorted'], list): # handle list of tuples                target_freq_dict = dict(composition['sorted'])            if target_freq_dict:                for aa, freq_val in sorted(target_freq_dict.items(), key=lambda item: item[1], reverse=True): # Sort by freq                    percentage = freq_val * 100                    if percentage >= highlight_threshold:                        print(f"  \033[1m{aa}: {percentage:.1f}%\033[0m")                    else:                        print(f"  {aa}: {percentage:.1f}%")                processed = True            elif not processed: # Fallback to iterating through dict items if no 'frequencies' or 'sorted'                for residue, value in sorted(composition.items(), key=lambda item: item[1] if isinstance(item[1], (int, float)) else -1, reverse=True):                    if not isinstance(value, (int, float)):                        continue # Skip non-numeric values like sub-dictionaries                    percentage = value # Assuming value is already percentage if not from freq_dict                    if 'frequencies' not in composition and 'sorted' not in composition: # If it's direct percentages                         pass # Keep as is                    else: # Should not happen if target_freq_dict was processed                         percentage = value * 100                    if percentage >= highlight_threshold:                        print(f"  \033[1m{residue}: {percentage:.1f}%\033[0m")                    else:                        print(f"  {residue}: {percentage:.1f}%")                processed = True        if not processed:            print(f"  [Info: Unexpected composition format or no data for {position}]")def calculate_helix_distances(distance_table):    """    Calculate the mean and standard deviation of distances to retinal for each position,    grouped by helix, using the GRN column names (N.YY format).    Args:        distance_table: DataFrame with distances (columns are GRN positions)    Returns:        dict: Dictionary with helix statistics    """    if distance_table.empty:        return {}    mean_distances = distance_table.mean(skipna=True)    std_distances = distance_table.std(skipna=True)    helix_stats = {}    for position in mean_distances.index:        pos_str = str(position)        if '.' in pos_str:            parts = pos_str.split('.')            if len(parts) == 2 and parts[0].isdigit() and 1 <= int(parts[0]) <= 7 and parts[1].replace('.', '', 1).isdigit():                helix_str_val = parts[0] # Renamed helix                if helix_str_val not in helix_stats:                    helix_stats[helix_str_val] = {'positions': [], 'means': [], 'stds': []}                # Ensure position exists in both mean and std, otherwise skip or use default for std                if position in mean_distances and position in std_distances:                    helix_stats[helix_str_val]['positions'].append(position)                    helix_stats[helix_str_val]['means'].append(mean_distances[position])                    helix_stats[helix_str_val]['stds'].append(std_distances[position])                elif position in mean_distances: # Position only in mean_distances                    helix_stats[helix_str_val]['positions'].append(position)                    helix_stats[helix_str_val]['means'].append(mean_distances[position])                    helix_stats[helix_str_val]['stds'].append(np.nan) # Or 0, depends on desired handling                    print(f"Warning: Position {position} missing in std_distances for helix {helix_str_val}")    for helix_str_val, data_dict in helix_stats.items(): # Renamed helix, data        if data_dict['positions']: # Ensure there are positions to sort            # Sort by numeric part of position string (e.g., 50 from 1.50)            def get_pos_num(p_str):                return float(str(p_str).split('.')[1])            sorted_indices = sorted(range(len(data_dict['positions'])),                                key=lambda i: get_pos_num(data_dict['positions'][i]))            data_dict['positions'] = [data_dict['positions'][i] for i in sorted_indices]            data_dict['means'] = [data_dict['means'][i] for i in sorted_indices]            data_dict['stds'] = [data_dict['stds'][i] for i in sorted_indices]            valid_means = [m for m in data_dict['means'] if pd.notna(m)]            if valid_means:                min_mean_val = min(valid_means)                min_idx = data_dict['means'].index(min_mean_val) # Find index of first occurrence                data_dict['closest_position'] = data_dict['positions'][min_idx]                data_dict['closest_mean'] = min_mean_val            else:                data_dict['closest_position'] = None                data_dict['closest_mean'] = None        else: # Handle cases where a helix might have no valid positions after filtering            data_dict['closest_position'] = None            data_dict['closest_mean'] = None    return helix_statsdef visualize_msa_distances(msa_results, output_dir="./", prefix=""):    """    Creates visualization plots for MSA distance data with standard deviation.    Args:        msa_results: Results dictionary from generate_grn_msa_tables function        output_dir: Directory to save plots        prefix: Prefix for output filenames    Returns:        Dictionary with paths to generated plots    """    os.makedirs(output_dir, exist_ok=True)    ca_distance_table = msa_results.get("ca_distance_table", pd.DataFrame()) # Use .get for safety    distance_table = msa_results.get("distance_table", pd.DataFrame())    output_files = {}    if not distance_table.empty:        helix_stats = calculate_helix_distances(distance_table)        print("Closest residues to retinal (all-atom distances):")        for helix_val in sorted(helix_stats.keys(), key=int):            if helix_stats[helix_val].get('closest_position'):                print(f"Helix {helix_val}: Position {helix_stats[helix_val]['closest_position']} "                      f"(distance: {helix_stats[helix_val]['closest_mean']:.2f}Å)")        all_plot = plot_distances_with_std(            distance_table, title="All-Atom Distances to Retinal", use_ca=False        )        all_path = os.path.join(output_dir, f"{prefix}all_atom_distances_std.png")        all_plot.savefig(all_path, dpi=300, bbox_inches='tight')        output_files["all_atom_distances_std"] = all_path        plt.close(all_plot)    else:        print("Skipping all-atom distance plot: distance_table is empty.")    if not ca_distance_table.empty:        ca_helix_stats = calculate_helix_distances(ca_distance_table)        print("\nClosest residues to retinal (CA atoms):")        for helix_val in sorted(ca_helix_stats.keys(), key=int):            if ca_helix_stats[helix_val].get('closest_position'):                print(f"Helix {helix_val}: Position {ca_helix_stats[helix_val]['closest_position']} "                      f"(distance: {ca_helix_stats[helix_val]['closest_mean']:.2f}Å)")        ca_plot = plot_distances_with_std(            ca_distance_table, title="CA Atom Distances to Retinal", use_ca=True        )        ca_path = os.path.join(output_dir, f"{prefix}ca_atom_distances_std.png")        ca_plot.savefig(ca_path, dpi=300, bbox_inches='tight')        output_files["ca_atom_distances_std"] = ca_path        plt.close(ca_plot)    else:        print("Skipping CA distance plot: ca_distance_table is empty.")    # Sequence logo plots    # Ensure 'ca_residue_table' or a suitable MSA table is present in msa_results    # The name 'ca_residue_table' might imply it's from CAs, but plot_helix_logo_plots expects sequence data.    # Let's assume msa_results["residue_table"] or msa_results["msa_table"] is more appropriate if it holds sequences.    residue_data_for_logos = msa_results.get("residue_table", msa_results.get("msa_table", pd.DataFrame()))    if not residue_data_for_logos.empty:        try:            # Try to ensure logomaker is available (already handled by top-level import)            print("[INFO] Creating sequence logo plots for positions around X.50")            logo_plot = plot_helix_logo_plots(                residue_table=residue_data_for_logos,                figsize=(20, 5)            )            logo_path = os.path.join(output_dir, f"{prefix}sequence_logos_x50.png")            logo_plot.savefig(logo_path, dpi=300, bbox_inches='tight')            output_files["sequence_logos_x50"] = logo_path            plt.close(logo_plot)            print(f"[INFO] Sequence logo plots (X.50) saved to {logo_path}")        except Exception as e:            print(f"[WARNING] Could not create sequence logo plots (X.50): {e}")            import traceback            traceback.print_exc()    else:        print("Skipping sequence logo plots (X.50): No suitable residue/MSA table found in msa_results.")    print(f"Distance visualizations saved to {output_dir}")    return output_filesdef create_combined_distance_logo_plot(distance_table, msa_df):    """    Create a combined figure with a distance line plot on top and a sequence logo below,    with precisely aligned x-axes for both dot notation (1.50) and x notation (1x50) GRN formats.    Args:        distance_table: DataFrame with distances for plotting (columns as GRN positions)        msa_df: Multiple sequence alignment DataFrame (columns as GRN positions)    Returns:        Matplotlib figure    """    import matplotlib.gridspec as gridspec # Local import    if distance_table.empty or msa_df.empty:        fig, ax = plt.subplots(figsize=(15,10))        ax.text(0.5,0.5, "Distance or MSA data is empty. Cannot create combined plot.",                ha='center', va='center', transform=ax.transAxes)        return fig    fig = plt.figure(figsize=(15, 10))    gs = gridspec.GridSpec(2, 1, height_ratios=[1, 0.6], hspace=0.05)    ax_top = fig.add_subplot(gs[0])    ax_bottom = fig.add_subplot(gs[1], sharex=ax_top) # Share x-axis    mean_distances = distance_table.mean(skipna=True)    def grn_sort_key(pos_val): # Renamed pos        pos_str = str(pos_val)        if pos_str.startswith('n.'):            parts = pos_str.split('.')            return (-1, float(parts[1]) if len(parts) > 1 and parts[1].replace('.', '', 1).isdigit() else 0)        if 'x' in pos_str:            parts = pos_str.split('x')            if parts[0].isdigit() and parts[1].replace('.', '', 1).isdigit():                return (int(parts[0]), int(parts[1])) # Keep second part as int if no decimal        if '.' in pos_str and not pos_str.startswith('L.') and not pos_str.startswith('c.'):            parts = pos_str.split('.')            if len(parts) == 2 and parts[0].isdigit() and parts[1].replace('.', '', 1).isdigit():                return (int(parts[0]), int(float(parts[1]))) # Ensure second part is float then int for sorting        if '.' in pos_str and len(pos_str) >= 4 and pos_str[0:2].isdigit() and not pos_str[2].isdigit(): # Loop AB.CCC (e.g. 12.003)            parts = pos_str.split('.')            if len(parts[0]) == 2 and parts[0].isdigit() and parts[1].replace('.', '', 1).isdigit():                 # Sort loops after helices, then by first part of loop, then second                 return (8, int(parts[0]), float('0.' + parts[1]))        if pos_str.startswith('L.'):            parts = pos_str.split('.')            return (80, float(parts[1]) if len(parts) > 1 and parts[1].replace('.', '', 1).isdigit() else 0)        if pos_str.startswith('c.'):            parts = pos_str.split('.')            return (90, float(parts[1]) if len(parts) > 1 and parts[1].replace('.', '', 1).isdigit() else 0)        return (999, 999) # Default for unknown    # Get common GRNs present in both distance and MSA, then sort them    common_grn_index = mean_distances.index.intersection(msa_df.columns)    if common_grn_index.empty:        ax_top.text(0.5,0.5, "No common GRNs between distance and MSA data.", ha='center', va='center')        ax_bottom.text(0.5,0.5, "", ha='center', va='center') # Clear bottom too        return fig    try: # Attempt GRN Utils sorting if available        from protos.processing.grn.grn_utils import sort_grns_str        sorted_common_grns = sort_grns_str(common_grn_index.astype(str).tolist())    except ImportError:        sorted_common_grns = sorted(common_grn_index.astype(str), key=grn_sort_key)    x_values = np.arange(len(sorted_common_grns))    y_values_dist = [mean_distances[grn] for grn in sorted_common_grns]    ax_top.plot(x_values, y_values_dist, 'o-', color='blue', linewidth=2)    ax_top.set_title('Distance to Retinal and Sequence Conservation', fontsize=14)    ax_top.set_ylabel('Average Distance to Retinal (Å)', fontsize=12)    ax_top.grid(True, alpha=0.3)    max_y_dist = (max(y_values_dist) if y_values_dist else 10)    for i, grn in enumerate(sorted_common_grns):        grn_str = str(grn)        # Check for .50 in dot notation or x50 in x notation        is_x50 = (grn_str.endswith('.50') and grn_str.split('.')[0].isdigit()) or \                   ('x50' in grn_str and grn_str.split('x')[0].isdigit())        if is_x50:            ax_top.axvline(x=i, color='gray', linestyle='--', alpha=0.7)            ax_top.text(i, max_y_dist * 0.95, grn_str,                        rotation=90, ha='center', va='top', fontsize=8)    plt.setp(ax_top.get_xticklabels(), visible=False) # Hide x-ticks on top plot    # --- Sequence Logo Plot (Bottom) ---    filtered_msa_for_logo = msa_df[sorted_common_grns] # Use sorted common GRNs for columns    # PWM calculation    amino_acids = list('ACDEFGHIKLMNPQRSTVWY')    # Initialize pwm_df with correct columns (amino_acids) and index matching x_values    pwm_df = pd.DataFrame(0.0, index=x_values, columns=amino_acids)    for i, grn_col in enumerate(sorted_common_grns): # Iterate using index i and GRN column name        aa_counts = Counter()        valid_aas_at_pos = 0        for seq_val in filtered_msa_for_logo[grn_col]:            if isinstance(seq_val, str) and len(seq_val) > 0 and seq_val[0] != '-':                aa = seq_val[0].upper()                if aa in amino_acids:                    aa_counts[aa] += 1                    valid_aas_at_pos +=1        if valid_aas_at_pos > 0:            for aa, count in aa_counts.items():                pwm_df.loc[i, aa] = count / valid_aas_at_pos # Use index i for pwm_df.loc    if not pwm_df.empty and pwm_df.sum().sum() > 0:        aa_colors_logo = { # Renamed aa_colors to avoid conflict            'A': OPSIN_COLORS['blue_light'], 'C': OPSIN_COLORS['yellow'],            'D': OPSIN_COLORS['red'], 'E': OPSIN_COLORS['red'],            'F': OPSIN_COLORS['blue_dark'], 'G': OPSIN_COLORS['orange'],            'H': OPSIN_COLORS['teal'], 'I': OPSIN_COLORS['blue_light'],            'K': OPSIN_COLORS['blue_dark'], 'L': OPSIN_COLORS['blue_light'],            'M': OPSIN_COLORS['blue_light'], 'N': OPSIN_COLORS['green'],            'P': OPSIN_COLORS['yellow'], 'Q': OPSIN_COLORS['green'],            'R': OPSIN_COLORS['blue_dark'], 'S': OPSIN_COLORS['green'],            'T': OPSIN_COLORS['green'], 'V': OPSIN_COLORS['blue_light'],            'W': OPSIN_COLORS['blue_dark'], 'Y': OPSIN_COLORS['blue_dark'],            '-': OPSIN_COLORS['gray_light'] # Though '-' is excluded from PWM        }        try:            lm_logo = logomaker.Logo(pwm_df, ax=ax_bottom, color_scheme=aa_colors_logo)            lm_logo.style_spines(visible=False)            # X-ticks are shared, labels set on bottom plot            ax_bottom.set_xticks(x_values)            ax_bottom.set_xticklabels(sorted_common_grns, rotation=90, fontsize=8)        except Exception as e_logo:            print(f"Error creating sequence logo for combined plot: {e_logo}")            ax_bottom.text(0.5,0.5, "Logo generation error", ha='center', va='center')            ax_bottom.set_xticks(x_values)            ax_bottom.set_xticklabels(sorted_common_grns, rotation=90, fontsize=8)    else:        ax_bottom.text(0.5, 0.5, "Insufficient data for sequence logo",                       ha='center', va='center', transform=ax_bottom.transAxes)        ax_bottom.set_xticks(x_values)        ax_bottom.set_xticklabels(sorted_common_grns, rotation=90, fontsize=8)    ax_bottom.set_xlabel('Position (GRN)', fontsize=12)    ax_bottom.set_ylabel('Information Content (bits)', fontsize=12)    ax_bottom.set_ylim(0, np.log2(len(amino_acids))) # Max possible bits    # Add matching vertical lines to bottom plot    for i, grn in enumerate(sorted_common_grns):        grn_str = str(grn)        is_x50 = (grn_str.endswith('.50') and grn_str.split('.')[0].isdigit()) or \                   ('x50' in grn_str and grn_str.split('x')[0].isdigit())        if is_x50:            ax_bottom.axvline(x=i, color='gray', linestyle='--', alpha=0.7)    # Ensure x-limits are tight around the plotted data    if x_values.size > 0 :        xlim_shared = (-0.5, x_values[-1] + 0.5)        ax_top.set_xlim(xlim_shared)        ax_bottom.set_xlim(xlim_shared)    plt.tight_layout(rect=[0, 0.03, 1, 0.95]) # Adjust overall layout    return figdef create_opsin_overview_plot(df, output_path=None, figsize=(16, 16)):    """    Create a circular overview plot of opsin structures with multiple rings showing    molecular function, domain, and experimental/predicted status.    Args:        df: DataFrame with opsin information, must include columns:            - molecular_function_normalized: Function category            - domain: Taxonomic domain            - experimentally_determined: Boolean flag for experimental structures            - short_name: Short identifier for each structure        output_path: Path to save the figure (optional)        figsize: Figure size tuple (width, height)    Returns:        Matplotlib figure with circular plot    """    df_copy = df.copy() # Renamed df to df_copy    df_copy['molecular_function_normalized'] = df_copy['molecular_function_normalized'].fillna('Unknown')    df_copy['domain'] = df_copy['domain'].fillna('Unknown')    # Sort by function primarily, then by domain, then by name for consistent ordering    df_sorted = df_copy.sort_values(by=['molecular_function_normalized', 'domain', 'short_name'], ignore_index=True)    N = len(df_sorted)    if N == 0:        fig, ax = plt.subplots(figsize=figsize)        ax.text(0.5, 0.5, "No data to plot.", ha='center', va='center', transform=ax.transAxes)        if output_path:            plt.savefig(output_path, dpi=300, bbox_inches='tight')        return fig    function_colors_dict = get_group_colors(df_sorted['molecular_function_normalized'].unique())    domain_colors_dict = {        'Bacteria': OPSIN_COLORS['red'], 'Eukaryota': OPSIN_COLORS['green'],        'Archaea': OPSIN_COLORS['yellow'], 'Virus': OPSIN_COLORS['blue_dark'],        'Synthetic': OPSIN_COLORS['orange'], 'Unknown': OPSIN_COLORS['gray_dark']    }    ring1_colors = [function_colors_dict.get(f, OPSIN_COLORS['gray_light'])                    for f in df_sorted['molecular_function_normalized']]    ring2_colors = [domain_colors_dict.get(d, OPSIN_COLORS['gray_light'])                    for d in df_sorted['domain']]    ring3_labels = ['•' if x else '' for x in df_sorted['experimentally_determined']]    ring4_labels = ['•'] * N # Assuming all structures in overview_df have a predicted counterpart or are themselves predictions    fig = plt.figure(figsize=figsize)    # Adjust main axes for plot and make space for legends    ax = fig.add_axes([0.05, 0.05, 0.7, 0.9]) # Left, bottom, width, height    R1_RADIUS, R2_RADIUS, R3_RADIUS, R4_RADIUS = 0.65, 0.85, 0.93, 0.98    SLICE_WIDTH = 0.18    DOT_WIDTH = 0.03    # Plot pies starting from top (90 degrees) and going clockwise    ax.pie([1] * N, colors=ring1_colors, radius=R1_RADIUS,           wedgeprops=dict(width=SLICE_WIDTH, edgecolor='white'), startangle=90, counterclock=False)    ax.pie([1] * N, colors=ring2_colors, radius=R2_RADIUS,           wedgeprops=dict(width=SLICE_WIDTH, edgecolor='white'), startangle=90, counterclock=False)    # For dot rings, adjust labeldistance and textprops for better alignment    _, texts3 = ax.pie([1] * N, labels=ring3_labels, radius=R3_RADIUS, labeldistance=1.02,                       wedgeprops=dict(width=DOT_WIDTH, edgecolor='white', facecolor='none'), # facecolor='none' for dots                       startangle=90, counterclock=False,                       textprops={'va':'center', 'ha':'center', 'fontsize': 16, 'color':'black'})    _, texts4 = ax.pie([1] * N, labels=ring4_labels, radius=R4_RADIUS, labeldistance=1.02,                       wedgeprops=dict(width=DOT_WIDTH, edgecolor='white', facecolor='none'),                       startangle=90, counterclock=False,                       textprops={'va':'center', 'ha':'center', 'fontsize': 16, 'color':'green'})    ax.set_title("Opsin Structures Overview", pad=30, fontsize=18) # Increased pad for title    # Create legends outside the pie chart area    # Filter out 'Unknown' from legends if desired    legend_elements_func = [Patch(facecolor=color, label=func)                            for func, color in sorted(function_colors_dict.items()) if func in df_sorted['molecular_function_normalized'].unique() and func != "Unknown"]    legend_elements_domain = [Patch(facecolor=color, label=domain_val) # Renamed domain                              for domain_val, color in sorted(domain_colors_dict.items()) if domain_val in df_sorted['domain'].unique() and domain_val != "Unknown"]    # For status, create more descriptive labels    legend_elements_status = [        Patch(facecolor='none', edgecolor='none', label='Experimental (• Black Dot)'), # Using Patch for consistent legend look        Patch(facecolor='none', edgecolor='none', label='Predicted    (• Green Dot)')    ]    # Add legends to the figure, positioning them to the right    # Use a dedicated axes for legends if they become too complex for fig.legend    leg_ax = fig.add_axes([0.72, 0.15, 0.25, 0.7]) # Axes for legends [left, bottom, width, height]    leg_ax.axis('off') # Turn off axis for legend axes    leg1 = leg_ax.legend(handles=legend_elements_func, title="Molecular Function",                         loc="upper left", fontsize=10, title_fontsize=12, frameon=False)    # Add subsequent legends, adjusting loc or using bbox_to_anchor if needed within leg_ax    # For simplicity here, stacking them. Better control with manual y positions or multiple legend axes.    current_y_offset = 0.85 # Starting y for the next legend (relative to leg_ax)    if legend_elements_domain:        leg2 = leg_ax.legend(handles=legend_elements_domain, title="Domain",                             loc="upper left", bbox_to_anchor=(0, current_y_offset), # Example offset                             fontsize=10, title_fontsize=12, frameon=False)        leg_ax.add_artist(leg1) # Re-add previous legends if they get overwritten by new legend() calls on same axes        current_y_offset -= 0.3 # Adjust offset based on legend size    if legend_elements_status:        leg3 = leg_ax.legend(handles=legend_elements_status, title="Status",                             loc="upper left", bbox_to_anchor=(0, current_y_offset),                             fontsize=10, title_fontsize=12, frameon=False)        if 'leg2' in locals() and leg2 is not None: leg_ax.add_artist(leg2) # Re-add previous        if leg1 is not None: leg_ax.add_artist(leg1)    if output_path:        plt.savefig(output_path, dpi=300, bbox_inches='tight')    return figdef plot_conservation_around_x50(residue_table, conservation_scores=None, figsize=(20, 10)):    """    Create sequence logo plots for 4 residues around X.50 positions in each helix (1-7),    based on residue conservation.    Args:        residue_table: DataFrame with residue information (ca_residue_table_grn)        conservation_scores: Dictionary of conservation scores by position (optional)        figsize: Figure size tuple (width, height)    Returns:        Matplotlib figure with 7 logo subplots showing conservation    """    from collections import Counter # Local import    if residue_table is None or residue_table.empty:        fig, ax = plt.subplots(figsize=(8, 5))        ax.text(0.5, 0.5, "No data available", ha='center', va='center', transform=ax.transAxes, fontsize=14)        return fig    window_size = 4    fig, axes = plt.subplots(1, 7, figsize=figsize, sharey=True)    valid_columns = []    for col in residue_table.columns:        col_str = str(col)        if '.' in col_str:            try:                helix_num_str = col_str.split('.')[0]                if helix_num_str.isdigit() and 1 <= int(helix_num_str) <= 7:                    valid_columns.append(col)            except ValueError: continue    filtered_table = residue_table[valid_columns]    if filtered_table.empty:        for i in range(7):            axes[i].text(0.5,0.5, f"No valid TM data for Helix {i+1}", ha='center', va='center', transform=axes[i].transAxes)        plt.tight_layout()        return fig    if conservation_scores is None:        conservation_scores = {}        for pos_val_str_filt in filtered_table.columns: # Renamed pos to pos_val_str_filt            aa_values = []            for cell in filtered_table[pos_val_str_filt].values:                if pd.isna(cell) or cell == '-': continue                if isinstance(cell, str) and len(cell) > 0:                    aa = cell[0].upper()                    if aa in 'ACDEFGHIKLMNPQRSTVWY': aa_values.append(aa)            if aa_values:                aa_counter = Counter(aa_values)                total = sum(aa_counter.values())                max_freq = max(aa_counter.values()) / total if total > 0 else 0                conservation_scores[pos_val_str_filt] = max_freq            else: conservation_scores[pos_val_str_filt] = 0.0    for helix_num in range(1, 8):        ax = axes[helix_num - 1]        pivot_pos_str = f"{helix_num}.50"        helix_positions = [col for col in filtered_table.columns if str(col).startswith(f"{helix_num}.")]        def position_sort_key(pos_val): return float(str(pos_val).split('.')[1])        helix_positions = sorted(helix_positions, key=position_sort_key)        actual_pivot_pos = pivot_pos_str        try: pivot_idx = helix_positions.index(pivot_pos_str)        except ValueError:            closest_positions = sorted([(abs(position_sort_key(pos_val) - 50.0), pos_val) for pos_val in helix_positions])            if closest_positions:                actual_pivot_pos = closest_positions[0][1]                pivot_idx = helix_positions.index(actual_pivot_pos)                print(f"[WARNING] Position {pivot_pos_str} for Helix {helix_num} not found, using {actual_pivot_pos} as pivot.")            else:                ax.text(0.5, 0.5, f"No data for Helix {helix_num}", ha='center', va='center', transform=ax.transAxes)                continue        start_idx = max(0, pivot_idx - window_size)        end_idx = min(len(helix_positions), pivot_idx + window_size + 1)        window_positions = helix_positions[start_idx:end_idx]        amino_acids = 'ACDEFGHIKLMNPQRSTVWY'        # Use integer index for logo_df to align with logomaker and xticks        logo_df = pd.DataFrame(0.0, index=range(len(window_positions)), columns=list(amino_acids))        for i_win, pos_val_str_win in enumerate(window_positions): # Renamed i, pos            aa_values = []            if pos_val_str_win in filtered_table.columns:                for cell in filtered_table[pos_val_str_win].values:                    if pd.isna(cell) or cell == '-': continue                    if isinstance(cell, str) and len(cell) > 0:                        aa = cell[0].upper()                        if aa in amino_acids: aa_values.append(aa)            if aa_values:                aa_counter = Counter(aa_values)                total = sum(aa_counter.values())                raw_freqs = {aa: count / total for aa, count in aa_counter.items()} if total > 0 else {}                cons_score_val = conservation_scores.get(pos_val_str_win, 0) # Renamed cons_score                # For logomaker, provide frequencies that sum to 1.                # The height of the stack can be controlled by `logo.scale_height` or by pre-calculating                # information content and providing that as a separate height vector.                # Here, we'll use raw frequencies and the default information content height calculation by logomaker.                # The text annotations will show the conservation score.                for aa, freq_val in raw_freqs.items(): # Renamed freq                    logo_df.loc[i_win, aa] = freq_val # Use integer index i_win        position_labels = []        pivot_num_val = float(str(actual_pivot_pos).split('.')[1])        for pos_val_str_win in window_positions:            pos_num_val = float(str(pos_val_str_win).split('.')[1])            offset = int(pos_num_val - pivot_num_val)            position_labels.append(offset)        if not logo_df.empty and logo_df.sum().sum() > 0:            try:                lm_logo = logomaker.Logo(logo_df, ax=ax, color_scheme='chemistry')                ax.set_title(f"Helix {helix_num}", color=HELIX_COLORS.get(helix_num, 'black'), fontweight='bold')                ax.set_xlabel("Offset from X.50", fontsize=10)                ax.set_xticks(range(len(window_positions))) # Use integer ticks                ax.set_xticklabels(position_labels, fontsize=9)                try:                    x50_plot_idx = window_positions.index(actual_pivot_pos)                    ax.axvline(x=x50_plot_idx, color=HELIX_COLORS.get(helix_num, 'gray'), linestyle='--', alpha=0.5)                except ValueError: pass                # Add conservation score and most frequent AA text                y_lim_curr = ax.get_ylim() # Current y-limits from logomaker                text_y_pos_score = y_lim_curr[0] - 0.1 * (y_lim_curr[1] - y_lim_curr[0]) # Below x-axis                text_y_pos_aa = y_lim_curr[0] - 0.25 * (y_lim_curr[1] - y_lim_curr[0])                for i_plot, pos_val_str_win in enumerate(window_positions): # Renamed i, pos                    cons_score_val = conservation_scores.get(pos_val_str_win, 0)                    if cons_score_val > 0:                        ax.text(i_plot, text_y_pos_score, f"{int(cons_score_val*100)}%",                                ha='center', fontsize=8, rotation=90, va='top')                    if cons_score_val > 0.4 and not logo_df.empty and i_plot < len(logo_df) and logo_df.loc[i_plot].sum() > 0:                        max_aa = logo_df.loc[i_plot].idxmax()                        ax.text(i_plot, text_y_pos_aa, max_aa, ha='center', fontweight='bold', fontsize=10)            except Exception as e_logo:                ax.text(0.5,0.5, f"Logo error", ha='center', va='center', transform=ax.transAxes)                print(f"Error plotting logo for Helix {helix_num}: {e_logo}")        else:            ax.text(0.5, 0.5, f"No AA data for Helix {helix_num} window", ha='center', va='center', transform=ax.transAxes)    for ax_iter in axes: # Renamed ax        ax_iter.set_ylim(-0.6, 2.1) # Adjust ylim to make space for text below    axes[0].set_ylabel("Information Content (bits)", fontsize=12)    plt.suptitle("Amino Acid Conservation around X.50 Positions (TM Helices 1-7)", fontsize=14, y=0.98)    plt.tight_layout(rect=[0, 0.03, 1, 0.95])    return fig